import org.apache.commons.csv.*;

import java.io.IOException;

public class TestBug {
    public static void main(String[] args) {
        try {
            final String code = "A,B,C,,\r\na,b,c,d,e\r\n";
            final CSVParser parser = CSVParser.parse(code, CSVFormat.EXCEL.withHeader());
            System.out.println("Header map: " + parser.getHeaderMap());
            for (CSVRecord record : parser.getRecords()) {
                System.out.println("Record values: " + java.util.Arrays.toString(record.values()));
                System.out.println("A: " + record.get("A"));
                System.out.println("B: " + record.get("B"));
                System.out.println("C: " + record.get("C"));
            }
            parser.close();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

